import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js";

// Imports locales (dentro del mismo directorio — Deno los resuelve correctamente)
import { SYSTEM_PROMPT, TOOLS, MODEL_CONFIG } from "./config.ts";
import { getModelAdapter } from "./model-adapter.ts";
import { 
  executeConsultarDisponibilidad, 
  executeCalcularPrecio, 
  executeAgendarCita, 
  executeDerivarAKelly,
  executeCancelarCita,
  executeReprogramarCita
} from "./tools.ts";

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

// Diccionario de ejecutores
const toolExecutors: Record<string, (args: any, ctx: any) => Promise<string>> = {
  consultar_disponibilidad: executeConsultarDisponibilidad,
  calcular_precio: (args: any, _ctx: any) => executeCalcularPrecio(args),
  agendar_cita: executeAgendarCita,
  derivar_a_kelly: executeDerivarAKelly,
  cancelar_cita: executeCancelarCita,
  reprogramar_cita: executeReprogramarCita,
};

async function sendWhatsAppResponse(to: string, text: string) {
  const apiKey = Deno.env.get("YCLOUD_API_KEY");
  const from = Deno.env.get("YCLOUD_PHONE_NUMBER_ID");

  if (!apiKey || !from) {
    console.error("Faltan credenciales de YCloud en el entorno");
    return;
  }

  try {
    await fetch("https://api.ycloud.com/v2/whatsapp/messages/send", {
      method: "POST",
      headers: {
        "X-API-Key": apiKey,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        from: from,
        to: to,
        type: "text",
        text: { body: text }
      })
    });
  } catch (err) {
    console.error("Error enviando mensaje por YCloud:", err);
  }
}

Deno.serve(async (req: Request) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    const supabaseUrl = Deno.env.get("SUPABASE_URL") ?? "";
    const supabaseKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? "";
    const supabase = createClient(supabaseUrl, supabaseKey);

    const body = await req.json();
    const { senderNumber, text } = body;

    if (!senderNumber || !text) {
      return new Response("Bad Request: missing senderNumber or text", { status: 400 });
    }

    console.log(`[Agent-Runner] Iniciando procesamiento para ${senderNumber}`);

    // 1. Obtener/Crear conversación activa
    let { data: conv } = await supabase
      .from('conversaciones')
      .select('*')
      .eq('telefono_contacto', senderNumber)
      .eq('estado', 'activa')
      .single();

    if (!conv) {
      const { data: newConv, error } = await supabase
        .from('conversaciones')
        .insert({
          telefono_contacto: senderNumber,
          canal: 'whatsapp',
          estado: 'activa',
          mensajes_raw: []
        })
        .select()
        .single();

      if (error) throw error;
      conv = newConv;
    }

    // Si la conversación está en modo handoff, la IA no debe responder.
    if (conv.handoff_activo) {
      console.log(`[Agent-Runner] Handoff activo para ${senderNumber}. Ignorando.`);
      return new Response(JSON.stringify({ status: "ignored_handoff" }), { status: 200, headers: corsHeaders });
    }

    // 2. Cargar historial y armar el nuevo mensaje del usuario
    let history: any[] = Array.isArray(conv.mensajes_raw) ? conv.mensajes_raw : [];

    // Inyectamos contexto temporal y de memoria condensada (si existe) para el modelo
    const nowGuayaquil = new Date().toLocaleString("es-EC", { timeZone: "America/Guayaquil" });
    const memoryContext = conv.historial_resumido ? `\n\n[MEMORIA ANTIGUA DEL PACIENTE RESUMIDA]:\n${conv.historial_resumido}` : "";

    const userMessage = { 
      role: 'user', 
      content: `[CONTEXTO SISTEMA: Hora actual: ${nowGuayaquil}]${memoryContext}\n\n[MENSAJE DEL USUARIO]:\n${text}` 
    };

    history.push(userMessage);

    // 3. Preparar el Adaptador de Modelo (lee directamente de Deno.env)
    const adapter = getModelAdapter();

    // 4. Iniciar el Loop Agéntico (máximo 5 iteraciones de herramientas para evitar loops infinitos)
    let agentFinished = false;
    let iteration = 0;
    const MAX_ITERATIONS = 5;

    while (!agentFinished && iteration < MAX_ITERATIONS) {
      iteration++;
      console.log(`[Agent-Runner] Iteración ${iteration}...`);

      const { text: llmText, toolCalls } = await adapter.chat({
        systemPrompt: SYSTEM_PROMPT, 
        messages: history, 
        tools: TOOLS, 
        maxTokens: MODEL_CONFIG.max_tokens_normal || 300
      });

      // Si hay texto dirigido al usuario, lo guardamos y lo enviamos a WA
      if (llmText) {
        history.push({ role: 'assistant', content: llmText });
        await sendWhatsAppResponse(senderNumber, llmText);
        agentFinished = true;
      }

      // Si el modelo decidió usar herramientas (Tool Calling)
      if (toolCalls && toolCalls.length > 0) {
        agentFinished = false; // El agente necesita ver los resultados de la herramienta

        // Guardar la intención de usar herramienta en el historial (necesario para la API)
        history.push({ role: 'assistant', content: '', tool_calls: toolCalls });

        for (const tool of toolCalls) {
          console.log(`[Agent-Runner] Ejecutando tool: ${tool.name}`, tool.input);
          let toolResultStr = "";

          if (toolExecutors[tool.name]) {
             const context = { 
               senderNumber, 
               conversacion_id: conv.id, 
               paciente_id: conv.paciente_id 
             };
             toolResultStr = await toolExecutors[tool.name](tool.input, context);
          } else {
             toolResultStr = JSON.stringify({ error: `Tool ${tool.name} no está implementada.` });
          }

          // Guardar resultado en formato compatible con las 3 APIs
          history.push({ 
            role: 'tool',
            name: tool.name,
            tool_call_id: tool.id,
            tool_use_id: tool.id,
            content: toolResultStr 
          });
        }
      } else if (!llmText) {
        // Si no hay tools ni texto, terminamos igualmente
        agentFinished = true;
      }
    }

    // 5. Guardar Memoria a Corto Plazo (y condensar si es necesario)
    const threshold = MODEL_CONFIG.history_condensation_threshold || 6;
    if (history.length >= threshold) {
      console.log(`[Agent-Runner] Límite de memoria alcanzado (${history.length}). Condensando...`);

      const summaryPrompt = "Eres un analista de datos. Resume esta conversación entre el usuario y la clínica en un párrafo breve. Conserva el perfil de usuario (nombre/síntomas/necesidad) y en qué parte del flujo se quedaron (ej. buscando fechas, yendo a pagar). Omite saludos triviales.";

      const sumResponse = await adapter.chat({
        systemPrompt: summaryPrompt, 
        messages: history.filter((h: any) => h.role === 'user' || h.role === 'assistant'), 
        tools: [], 
        maxTokens: 250
      });
      const newSummary = sumResponse.text;

      await supabase
        .from('conversaciones')
        .update({ 
          mensajes_raw: [], 
          historial_resumido: newSummary 
        })
        .eq('id', conv.id);

    } else {
      await supabase
        .from('conversaciones')
        .update({ mensajes_raw: history })
        .eq('id', conv.id);
    }

    return new Response(JSON.stringify({ status: "success", historyLength: history.length }), { headers: corsHeaders, status: 200 });

  } catch (err: any) {
    console.error("Error crítico en Agent-Runner:", err);
    return new Response(JSON.stringify({ error: err.message }), { status: 500, headers: corsHeaders });
  }
});

/**
 * model-adapter.ts — Capa de abstracción LLM para Deno Edge Functions.
 * Soporta Claude, OpenAI y Gemini con interfaz unificada.
 */

const PROVIDERS: Record<string, { defaultModel: string; endpoint: string }> = {
  anthropic: {
    defaultModel: "claude-haiku-4-5-20250315",
    endpoint: "https://api.anthropic.com/v1/messages",
  },
  openai: {
    defaultModel: "gpt-4o-mini",
    endpoint: "https://api.openai.com/v1/chat/completions",
  },
  gemini: {
    defaultModel: "gemini-2.0-flash",
    endpoint: "https://generativelanguage.googleapis.com/v1beta",
  },
};

// ─── Conversiones de herramientas ─────────────────────────────────────────────

function toolsToOpenAI(tools: any[]) {
  return tools.map((t) => ({
    type: "function",
    function: { name: t.name, description: t.description, parameters: t.input_schema },
  }));
}

function toolsToGemini(tools: any[]) {
  return [{ functionDeclarations: tools.map((t) => ({ name: t.name, description: t.description, parameters: t.input_schema })) }];
}

// ─── Conversiones de mensajes ─────────────────────────────────────────────────

function messagesToAnthropic(messages: any[]) {
  return messages.map((msg) => {
    if (msg.role === "tool_result" || msg.role === "tool") {
      return {
        role: "user",
        content: [{ type: "tool_result", tool_use_id: msg.tool_use_id || msg.tool_call_id, content: msg.content }],
      };
    }
    if (msg.role === "assistant" && msg.tool_calls) {
      return {
        role: "assistant",
        content: [
          ...(msg.content ? [{ type: "text", text: msg.content }] : []),
          ...msg.tool_calls.map((tc: any) => ({ type: "tool_use", id: tc.id, name: tc.name, input: tc.input || tc.arguments || {} })),
        ],
      };
    }
    return { role: msg.role, content: msg.content };
  });
}

function messagesToOpenAI(systemPrompt: string, messages: any[]) {
  const out: any[] = [{ role: "system", content: systemPrompt }];
  for (const msg of messages) {
    if (msg.role === "tool_result" || msg.role === "tool") {
      out.push({ role: "tool", tool_call_id: msg.tool_use_id || msg.tool_call_id, content: typeof msg.content === "string" ? msg.content : JSON.stringify(msg.content) });
    } else if (msg.role === "assistant" && msg.tool_calls) {
      out.push({
        role: "assistant", content: msg.content || null,
        tool_calls: msg.tool_calls.map((tc: any) => ({
          id: tc.id, type: "function",
          function: { name: tc.name, arguments: typeof tc.input === "string" ? tc.input : JSON.stringify(tc.input || tc.arguments || {}) },
        })),
      });
    } else {
      out.push({ role: msg.role, content: msg.content });
    }
  }
  return out;
}

function messagesToGemini(messages: any[]) {
  const out: any[] = [];
  for (const msg of messages) {
    if (msg.role === "user") {
      out.push({ role: "user", parts: [{ text: msg.content }] });
    } else if (msg.role === "assistant") {
      const parts: any[] = [];
      if (msg.content) parts.push({ text: msg.content });
      if (msg.tool_calls) {
        for (const tc of msg.tool_calls) {
          parts.push({ functionCall: { name: tc.name, args: tc.input || tc.arguments || {} } });
        }
      }
      out.push({ role: "model", parts });
    } else if (msg.role === "tool_result" || msg.role === "tool") {
      out.push({ role: "function", parts: [{ functionResponse: { name: msg.name || msg.tool_name || "unknown", response: { result: msg.content } } }] });
    }
  }
  return out;
}

// ─── Normalización de respuestas ──────────────────────────────────────────────

function normalizeAnthropic(data: any) {
  const text = data.content?.filter((c: any) => c.type === "text").map((c: any) => c.text).join("") || null;
  const toolCalls = data.content?.filter((c: any) => c.type === "tool_use").map((c: any) => ({ id: c.id, name: c.name, input: c.input, arguments: c.input })) || [];
  return { text, toolCalls, usage: { input: data.usage?.input_tokens || 0, output: data.usage?.output_tokens || 0 } };
}

function normalizeOpenAI(data: any) {
  const msg = data.choices?.[0]?.message;
  const toolCalls = (msg?.tool_calls || []).map((tc: any) => ({
    id: tc.id, name: tc.function.name, input: JSON.parse(tc.function.arguments || "{}"), arguments: JSON.parse(tc.function.arguments || "{}"),
  }));
  return { text: msg?.content || null, toolCalls, usage: { input: data.usage?.prompt_tokens || 0, output: data.usage?.completion_tokens || 0 } };
}

function normalizeGemini(data: any) {
  const parts = data.candidates?.[0]?.content?.parts || [];
  const text = parts.filter((p: any) => p.text).map((p: any) => p.text).join("") || null;
  const toolCalls = parts.filter((p: any) => p.functionCall).map((p: any, i: number) => ({
    id: `gemini_${Date.now()}_${i}`, name: p.functionCall.name, input: p.functionCall.args || {}, arguments: p.functionCall.args || {},
  }));
  return { text, toolCalls, usage: { input: data.usageMetadata?.promptTokenCount || 0, output: data.usageMetadata?.candidatesTokenCount || 0 } };
}

// ─── Llamadas API ─────────────────────────────────────────────────────────────

async function callAnthropic(apiKey: string, model: string, systemPrompt: string, messages: any[], tools: any[], maxTokens: number) {
  const body: any = {
    model, max_tokens: maxTokens,
    system: [{ type: "text", text: systemPrompt, cache_control: { type: "ephemeral" } }],
    messages: messagesToAnthropic(messages),
  };
  if (tools.length > 0) body.tools = tools;

  const res = await fetch(PROVIDERS.anthropic.endpoint, {
    method: "POST",
    headers: { "Content-Type": "application/json", "x-api-key": apiKey, "anthropic-version": "2023-06-01", "anthropic-beta": "prompt-caching-2024-07-31" },
    body: JSON.stringify(body),
  });
  if (!res.ok) throw new Error(`Anthropic ${res.status}: ${await res.text()}`);
  return normalizeAnthropic(await res.json());
}

async function callOpenAI(apiKey: string, model: string, systemPrompt: string, messages: any[], tools: any[], maxTokens: number) {
  const body: any = { model, max_tokens: maxTokens, messages: messagesToOpenAI(systemPrompt, messages) };
  if (tools.length > 0) body.tools = toolsToOpenAI(tools);

  const res = await fetch(PROVIDERS.openai.endpoint, {
    method: "POST",
    headers: { "Content-Type": "application/json", "Authorization": `Bearer ${apiKey}` },
    body: JSON.stringify(body),
  });
  if (!res.ok) throw new Error(`OpenAI ${res.status}: ${await res.text()}`);
  return normalizeOpenAI(await res.json());
}

async function callGemini(apiKey: string, model: string, systemPrompt: string, messages: any[], tools: any[], maxTokens: number) {
  const endpoint = `${PROVIDERS.gemini.endpoint}/models/${model}:generateContent?key=${apiKey}`;
  const body: any = {
    systemInstruction: { parts: [{ text: systemPrompt }] },
    contents: messagesToGemini(messages),
    generationConfig: { maxOutputTokens: maxTokens },
  };
  if (tools.length > 0) body.tools = toolsToGemini(tools);

  const res = await fetch(endpoint, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`Gemini ${res.status}: ${await res.text()}`);
  return normalizeGemini(await res.json());
}

// ─── Factory ──────────────────────────────────────────────────────────────────

type ChatParams = { systemPrompt: string; messages: any[]; tools?: any[]; maxTokens?: number };

export function createModelAdapter(provider: string, apiKey: string, model?: string) {
  const config = PROVIDERS[provider];
  if (!config) throw new Error(`Proveedor no soportado: ${provider}`);
  const selectedModel = model || config.defaultModel;

  const callFn: Record<string, typeof callAnthropic> = { anthropic: callAnthropic, openai: callOpenAI, gemini: callGemini };

  return {
    provider,
    model: selectedModel,
    async chat({ systemPrompt, messages, tools = [], maxTokens = 300 }: ChatParams) {
      return callFn[provider](apiKey, selectedModel, systemPrompt, messages, tools, maxTokens);
    },
  };
}

/**
 * Lee AI_PROVIDER y API keys del entorno Deno y retorna un adaptador listo.
 */
export function getModelAdapter() {
  const provider = Deno.env.get("AI_PROVIDER") || "anthropic";
  const keyMap: Record<string, string | undefined> = {
    anthropic: Deno.env.get("ANTHROPIC_API_KEY"),
    openai: Deno.env.get("OPENAI_API_KEY"),
    gemini: Deno.env.get("GEMINI_API_KEY"),
  };
  const modelMap: Record<string, string | undefined> = {
    anthropic: Deno.env.get("ANTHROPIC_MODEL"),
    openai: Deno.env.get("OPENAI_MODEL"),
    gemini: Deno.env.get("GEMINI_MODEL"),
  };
  const apiKey = keyMap[provider];
  if (!apiKey) throw new Error(`API key no configurada para proveedor: ${provider}`);
  return createModelAdapter(provider, apiKey, modelMap[provider]);
}

import { createClient } from "jsr:@supabase/supabase-js";

/**
 * supabase/functions/agent-runner/tools.ts
 *
 * Implementación de las herramientas para el Agent Loop de Sofía.
 */

// URL del propio proyecto de supabase para llamar a edge functions internas
const SUPABASE_URL = Deno.env.get("SUPABASE_URL") || "";
const SUPABASE_ANON_KEY = Deno.env.get("SUPABASE_ANON_KEY") || "";

/**
 * Llama a la Edge Function 'calcular-precio' previamente construida.
 * Devuelve un string JSON para el LLM.
 */
export async function executeCalcularPrecio(args: any): Promise<string> {
  const { servicio_id, zona } = args;

  if (!servicio_id || !zona) {
    return JSON.stringify({ error: "Faltan parámetros: servicio_id o zona" });
  }

  try {
    const url = `${SUPABASE_URL}/functions/v1/calcular-precio`;
    const res = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
      },
      body: JSON.stringify({ servicio_id, zona })
    });

    if (!res.ok) {
      const errBody = await res.text();
      console.error("Error from calcular-precio function:", errBody);
      return JSON.stringify({ error: `Fallo al calcular precio: HTTP ${res.status}` });
    }

    const data = await res.json();
    return JSON.stringify(data);
  } catch (err: any) {
    console.error("Fetch error calling calcular-precio:", err);
    return JSON.stringify({ error: `Fallo interno al contactar calculador: ${err.message}` });
  }
}

function getSupabase() {
  const supabaseUrl = Deno.env.get("SUPABASE_URL") ?? "";
  const supabaseKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") ?? Deno.env.get("SUPABASE_ANON_KEY") ?? "";
  return createClient(supabaseUrl, supabaseKey);
}

/**
 * Consulta la disponibilidad de agenda en Supabase.
 * Retorna las fechas y horas libres excluyendo domingos, feriados (tarde) y slots ocupados.
 */
export async function executeConsultarDisponibilidad(args: any): Promise<string> {
  const { fecha_inicio, fecha_fin } = args; // modalidad puede ignorarse para disponibilidad porque el calendario es el mismo
  if (!fecha_inicio || !fecha_fin) {
    return JSON.stringify({ error: "Faltan parámetros: fecha_inicio o fecha_fin" });
  }

  try {
    const supabase = getSupabase();

    // 1. Consultar citas en este periodo que no estén canceladas u omitidas
    const { data: citas, error: errorCitas } = await supabase
      .from('citas')
      .select('fecha, hora, estado')
      .gte('fecha', fecha_inicio)
      .lte('fecha', fecha_fin)
      .not('estado', 'in', '("cancelada", "no_show")');

    if (errorCitas) throw errorCitas;

    // 2. Consultar feriados
    const { data: feriados, error: errorFeriados } = await supabase
      .from('feriados')
      .select('fecha')
      .gte('fecha', fecha_inicio)
      .lte('fecha', fecha_fin);

    if (errorFeriados) throw errorFeriados;

    const occupiedSet = new Set();
    citas?.forEach((cita: any) => {
      // hora viene como 'HH:MM:SS', nos quedamos con 'HH:MM'
      const timeStr = cita.hora.substring(0, 5); 
      occupiedSet.add(`${cita.fecha}_${timeStr}`);
    });

    const feriadoSet = new Set(feriados?.map((f: any) => f.fecha));

    // 3. Generar slots libres
    const startObj = new Date(fecha_inicio + "T00:00:00");
    const endObj = new Date(fecha_fin + "T00:00:00");
    let current = new Date(startObj);

    let slotsLibres: Record<string, string[]> = {};
    let dayCount = 0;

    // Para evitar dar slots en el pasado el día de "hoy"
    const nowLocalStr = new Date().toLocaleString("en-US", { timeZone: "America/Guayaquil" });
    const localNow = new Date(nowLocalStr);
    const todayStr = localNow.getFullYear() + "-" + String(localNow.getMonth() + 1).padStart(2, '0') + "-" + String(localNow.getDate()).padStart(2, '0');
    const currentHourStr = String(localNow.getHours()).padStart(2, '0') + ":" + String(localNow.getMinutes()).padStart(2, '0');

    while (current <= endObj && dayCount <= 14) {
      const dateStr = current.getFullYear() + "-" + String(current.getMonth() + 1).padStart(2, '0') + "-" + String(current.getDate()).padStart(2, '0');
      const dayOfWeek = current.getDay(); // 0 es Domingo

      if (dayOfWeek !== 0) { // Ignorar domingos
        let isFeriado = feriadoSet.has(dateStr);
        let allowedSlots: string[] = [];

        // Franja mañana: 08:00 a 11:30 (ya que citas pueden durar hasta 40m, 11:30 termina 12:10)
        const morningSlots = ["08:00", "08:30", "09:00", "09:30", "10:00", "10:30", "11:00", "11:30"];
        const afternoonSlots = ["15:00", "15:30", "16:00", "16:30"];

        allowedSlots.push(...morningSlots);

        // Sabados y Feriados SOLO trabajan en la mañana
        if (!isFeriado && dayOfWeek !== 6) {
          allowedSlots.push(...afternoonSlots);
        }

        const validSlots = allowedSlots.filter(timeSlot => {
          // Descartar citas del mismo día que ya pasaron
          if (dateStr === todayStr && timeSlot <= currentHourStr) {
             return false;
          }
          return !occupiedSet.has(`${dateStr}_${timeSlot}`);
        });

        if (validSlots.length > 0) {
          slotsLibres[dateStr] = validSlots;
        }
      }

      current.setDate(current.getDate() + 1);
      dayCount++;
    }

    return JSON.stringify(slotsLibres);
  } catch (err: any) {
    console.error("Error executing consultar_disponibilidad:", err);
    return JSON.stringify({ error: `Hubo un error al consultar disponibilidad: ${err.message}` });
  }
}

/**
 * Registra un paciente y le agenda una cita.
 * Si la zona es 'sur', la cita se confirma. Si no, queda en 'pendiente_pago'.
 */
export async function executeAgendarCita(args: any, context: any): Promise<string> {
  const {
    paciente_nombre, paciente_fecha_nacimiento, paciente_telefono, paciente_email,
    servicio_id, fecha, hora, modalidad, zona, motivo
  } = args;

  if (!paciente_nombre || !paciente_telefono || !servicio_id || !fecha || !hora || !modalidad || !zona) {
    return JSON.stringify({ error: "Faltan parámetros requeridos para agendar la cita" });
  }

  try {
    const supabase = getSupabase();
    const { conversacion_id } = context ?? {};

    // 1. Verificar si el slot no fue ocupado en el último segundo
    const { data: slotCheck } = await supabase
      .from('citas')
      .select('id')
      .eq('fecha', fecha)
      .eq('hora', hora + ':00') // Las DBs suelen guardar esto con segundos (00)
      .not('estado', 'in', '("cancelada", "no_show")');

    if (slotCheck && slotCheck.length > 0) {
      return JSON.stringify({ 
        error: "El slot ya fue ocupado. Por favor, realiza otra consultar_disponibilidad y ofrécele al paciente otras opciones." 
      });
    }

    // 2. Buscar paciente o crearlo (el teléfono es único según esquema)
    // Usamos select + insert/update en lugar de upsert directo para mayor control
    let pacienteId;
    const { data: existingPatient } = await supabase
      .from('pacientes')
      .select('id')
      .eq('telefono', paciente_telefono)
      .single();

    if (existingPatient) {
      pacienteId = existingPatient.id;
      // Opcional: Actualizar datos
      await supabase.from('pacientes').update({ 
        nombre: paciente_nombre,
        fecha_nacimiento: paciente_fecha_nacimiento || null,
        email: paciente_email || null,
        zona: zona
      }).eq('id', pacienteId);
    } else {
      const { data: newPatient, error: newError } = await supabase
        .from('pacientes')
        .insert({
          nombre: paciente_nombre,
          fecha_nacimiento: paciente_fecha_nacimiento || null,
          telefono: paciente_telefono,
          email: paciente_email || null,
          zona: zona
        })
        .select()
        .single();

      if (newError) throw newError;
      pacienteId = newPatient.id;
    }

    // 3. Crear la Cita
    const estadoCita = zona === 'sur' ? 'confirmada' : 'pendiente_pago';

    const { data: citaData, error: citaError } = await supabase
      .from('citas')
      .insert({
        paciente_id: pacienteId,
        servicio: servicio_id,
        fecha: fecha,
        hora: hora,
        duracion_min: 30,
        estado: estadoCita,
        modalidad: modalidad
      })
      .select()
      .single();

    if (citaError) throw citaError;

    // 4. Vincular la conversación al paciente creado/encontrado
    if (conversacion_id) {
      const { error: conversacionError } = await supabase
        .from('conversaciones')
        .update({ paciente_id: pacienteId })
        .eq('id', conversacion_id);

      if (conversacionError) throw conversacionError;
    }

    // Si confirmada, podemos inyectar `monto_adelanto: 0`. Si pendiente_pago el LLM recordará el monto.
    return JSON.stringify({
      success: true,
      cita_id: citaData.id,
      estado: estadoCita,
      mensaje: estadoCita === 'confirmada' 
        ? "Cita confirmada (sin adelanto por sistema)." 
        : "Cita reservada, pendiente de recibir el pago de adelanto por transferencia."
    });

  } catch (err: any) {
    console.error("Error agendando cita:", err);
    return JSON.stringify({ error: `Hubo un error al registrar la cita: ${err.message}` });
  }
}

/**
 * Escala la consulta a Telegram para que Kelly atienda en persona (Handoff).
 */
export async function executeDerivarAKelly(args: any, context: any): Promise<string> {
  const { motivo, nivel_urgencia, historial_resumido } = args;
  const { paciente_id, conversacion_id, senderNumber } = context;

  if (!motivo || !historial_resumido) {
    return JSON.stringify({ error: "Motivo y resumen histórico son obligatorios" });
  }

  try {
    const supabase = getSupabase();

    // 1. Activar Handoff en la conversación
    if (conversacion_id) {
      await supabase
        .from('conversaciones')
        .update({ handoff_activo: true })
        .eq('id', conversacion_id);
    }

    // 2. Crear registro de Handoff
    let handoffId = null;
    if (paciente_id && conversacion_id) {
      const { data: handoffData } = await supabase
        .from('handoffs')
        .insert({
          conversacion_id: conversacion_id,
          paciente_id: paciente_id,
          motivo: motivo,
          nivel_urgencia: nivel_urgencia || 'medio',
          estado: 'activo'
        })
        .select('id')
        .single();
      if (handoffData) handoffId = handoffData.id;
    }

    // 3. Notificar a Telegram
    // Invocaremos al webhook de Telegram u optaremos por fetch directo a la api si telegram.js es importable localmente 
    // Para Deno es mejor un POST a una internal route de Telegram si existe, pero como telegram.js está en /lib,
    // es un módulo Node de Next. Llamemos al bot directo desde aquí (necesitamos el token).
    const telegramToken = Deno.env.get("TELEGRAM_BOT_TOKEN");
    const chatId = Deno.env.get("TELEGRAM_CHAT_ID");

    if (telegramToken && chatId) {
      const url = `https://api.telegram.org/bot${telegramToken}/sendMessage`;
      const txt = `
🚨 <b>ALERTA DE HANDOFF</b> 🚨
<b>Paciente:</b> ${senderNumber}
<b>Nivel:</b> ${nivel_urgencia}

<b>Motivo:</b> ${motivo}
<b>Contexto IA:</b> ${historial_resumido}

Por favor, contesta a este paciente desde tu WhatsApp Business oficial ahora.
`.trim();

      const options = {
         reply_markup: {
           inline_keyboard: [
              [{ text: "✅ Terminé la atención (Retomar IA)", callback_data: `handoff_done_${conversacion_id || 'none'}` }]
           ]
         }
      };

      await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ chat_id: chatId, text: txt, parse_mode: "HTML", reply_markup: options.reply_markup })
      });
    }

    return JSON.stringify({
      success: true,
      mensaje_interno: "Notificación enviada a la doctora. Indica al usuario educadamente que será contactado brevemente por ella y detén la conversación."
    });

  } catch (err: any) {
    console.error("Error derivando a kelly:", err);
    return JSON.stringify({ error: `Hubo un error en derivación técnica: ${err.message}` });
  }
}

export async function executeCancelarCita(args: any, context: any): Promise<string> {
  const { motivo } = args;
  const { paciente_id } = context;

  if (!paciente_id) {
    return JSON.stringify({ error: "No se identificó al paciente. Usa derivar_a_kelly." });
  }

  try {
    const supabase = getSupabase();
    // Obtener cita futura no cancelada/no_show
    const { data: cita } = await supabase
      .from("citas")
      .select("id, fecha, hora")
      .eq("paciente_id", paciente_id)
      .in("estado", ["confirmada", "pendiente_pago"])
      .order("fecha", { ascending: true })
      .order("hora", { ascending: true })
      .limit(1)
      .single();

    if (!cita) {
      return JSON.stringify({ error: "No se encontró ninguna cita activa para este paciente. Infórmale que no ves citas a su nombre." });
    }

    const fechaCita = new Date(`${cita.fecha}T${cita.hora}`);
    const timeDiffMs = fechaCita.getTime() - new Date().getTime();
    const isLessThan24h = timeDiffMs < 24 * 60 * 60 * 1000;

    if (isLessThan24h) {
      return JSON.stringify({ 
        error: "política_incumplida", 
        mensaje_interno: `Falta menos de 24h para la cita (Quedan ${Math.round(timeDiffMs / 3600000)}h). Informa al paciente que por políticas no puedes cancelarlo tú y transfiérelo usando derivar_a_kelly.` 
      });
    }

    // Cancelar en DB
    await supabase.from("citas").update({ estado: "cancelada" }).eq("id", cita.id);

    return JSON.stringify({ success: true, mensaje_interno: "Cita cancelada exitosamente. Comunícale la confirmación." });
  } catch (err: any) {
    return JSON.stringify({ error: `Fallo al cancelar: ${err.message}` });
  }
}

export async function executeReprogramarCita(args: any, context: any): Promise<string> {
  const { nueva_fecha, nueva_hora, motivo } = args;
  const { paciente_id } = context;

  if (!paciente_id) return JSON.stringify({ error: "No se identificó al paciente." });

  try {
    const supabase = getSupabase();

    // Obtener cita futura
    const { data: cita } = await supabase
      .from("citas")
      .select("id, fecha, hora")
      .eq("paciente_id", paciente_id)
      .in("estado", ["confirmada", "pendiente_pago"])
      .order("fecha", { ascending: true })
      .order("hora", { ascending: true })
      .limit(1)
      .single();

    if (!cita) {
      return JSON.stringify({ error: "No se encontró ninguna cita activa para reprogramar." });
    }

    // Identificar si es paciente nuevo (1 sola cita en la vida) o habitual (más citas confirmadas)
    const { count } = await supabase
      .from("citas")
      .select("id", { count: "exact" })
      .eq("paciente_id", paciente_id)
      .eq("estado", "completada");

    const isHabitual = (count && count > 0) ? true : false;
    const minHours = isHabitual ? 24 : 48;

    const fechaCita = new Date(`${cita.fecha}T${cita.hora}`);
    const timeDiffMs = fechaCita.getTime() - new Date().getTime();
    const hoursLeft = timeDiffMs / 3600000;

    // Verificar si ya pasó la cita (No-Show situation detected here by time)
    if (hoursLeft < 0) {
      // Enviar como no_show
      await supabase.from("citas").update({ estado: "no_show" }).eq("id", cita.id);
      return JSON.stringify({ 
        error: "no_show_detectado", 
        mensaje_interno: "El usuario escribió para reprogramar después de la hora de la cita. Marca como no_show usando derivar_a_kelly para que le cobren multa." 
      });
    }

    if (hoursLeft < minHours) {
      return JSON.stringify({ 
        error: "política_incumplida", 
        mensaje_interno: `Paciente ${isHabitual?'Habitual (req 24h)':'Nuevo (req 48h)'}. Faltan solo ${Math.round(hoursLeft)}h. Informa al paciente que no cumple política y deriva a Kelly usando derivar_a_kelly con historial_resumido.` 
      });
    }

    // Reprogramar en DB
    // Primero verificar slot libre
    const { data: slotCheck } = await supabase
      .from('citas')
      .select('id')
      .eq('fecha', nueva_fecha)
      .eq('hora', nueva_hora + ':00')
      .not('estado', 'in', '("cancelada", "no_show")');

    if (slotCheck && slotCheck.length > 0) {
      return JSON.stringify({ error: "El nuevo slot ya está ocupado. Intenta con otra fecha/hora." });
    }

    await supabase
      .from("citas")
      .update({ fecha: nueva_fecha, hora: nueva_hora })
      .eq("id", cita.id);

    return JSON.stringify({ success: true, mensaje_interno: "Cita reprogramada exitosamente. Confírmaselo al paciente." });
  } catch (err: any) {
    return JSON.stringify({ error: `Fallo al reprogramar: ${err.message}` });
  }
}
